import { useState, useEffect } from "react";
import "../assets/css/hero.css";

const HeroButton = () => {
  const [buttonText, setButtonText] = useState("Domyślny tekst");
  const [buttonHref, setButtonHref] = useState("#");

  useEffect(() => {
    console.log("Załadowanie pliku JSON...");
    fetch("/conf/hero/config.json")  // Bez window.location.origin
      .then((response) => {
        if (!response.ok) {
          console.error("Nie udało się załadować pliku JSON", response);
          throw new Error("Błąd ładowania JSON");
        }
        return response.json();
      })
      .then((data) => {
        console.log("Załadowane dane:", data);
        const section = data.find((item) => item["section-id"] === "hero-button");

        if (section) {
          setButtonText(section.text || "Domyślny tekst");
          setButtonHref(section.href || "#");
        } else {
          console.log("Nie znaleziono sekcji z id hero-button");
        }
      })
      .catch((error) => {
        console.error("Błąd ładowania pliku JSON:", error);
      });
  }, []);

  return (
    <a href={buttonHref} className="hero-button-link">
      <button className="hero-button">{buttonText}</button>
    </a>
  );
};

export default HeroButton;
